import torch; import torch.nn as nn; import json; import sys; import logging; from datetime import datetime; logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s'); logger = logging.getLogger(__name__); start_time = datetime.now(); logger.info('Starting transformer model instantiation for IDSL_MINT'); arch_config = json.load(open('{inputs.arch_config}')); sample_spectrum = torch.load('{inputs.sample_spectrum}'); embedding_dim = arch_config.get('embedding_dim', 256); num_heads = arch_config.get('num_heads', 8); num_layers = arch_config.get('num_layers', 4); ff_hidden_dim = arch_config.get('ff_hidden_dim', 1024); dropout_rate = arch_config.get('dropout_rate', 0.1); logger.info(f'Config: embedding_dim={embedding_dim}, num_heads={num_heads}, num_layers={num_layers}, ff_hidden_dim={ff_hidden_dim}, dropout_rate={dropout_rate}'); class MultiHeadAttention(nn.Module):
    def __init__(self, embedding_dim, num_heads, dropout_rate):
        super().__init__(); self.embedding_dim = embedding_dim; self.num_heads = num_heads; self.head_dim = embedding_dim // num_heads; self.query = nn.Linear(embedding_dim, embedding_dim); self.key = nn.Linear(embedding_dim, embedding_dim); self.value = nn.Linear(embedding_dim, embedding_dim); self.output_proj = nn.Linear(embedding_dim, embedding_dim); self.dropout = nn.Dropout(dropout_rate)
    def forward(self, x):
        B, T, D = x.shape; Q = self.query(x).view(B, T, self.num_heads, self.head_dim).transpose(1, 2); K = self.key(x).view(B, T, self.num_heads, self.head_dim).transpose(1, 2); V = self.value(x).view(B, T, self.num_heads, self.head_dim).transpose(1, 2); scores = torch.matmul(Q, K.transpose(-2, -1)) / (self.head_dim ** 0.5); attn_weights = torch.softmax(scores, dim=-1); attn_weights = self.dropout(attn_weights); context = torch.matmul(attn_weights, V); context = context.transpose(1, 2).contiguous().view(B, T, D); return self.output_proj(context)
class FeedForward(nn.Module):
