        super().__init__(); self.linear1 = nn.Linear(embedding_dim, ff_hidden_dim); self.relu = nn.ReLU(); self.linear2 = nn.Linear(ff_hidden_dim, embedding_dim); self.dropout = nn.Dropout(dropout_rate)
    def forward(self, x):
